8	import io.fabric8.kubernetes.client.CustomResource;
9	import io.strimzi.api.annotations.ApiVersion;
10	import io.strimzi.api.annotations.DeprecatedProperty;
11	import io.strimzi.api.annotations.DeprecatedType;
12	import io.strimzi.crdgenerator.annotations.AddedIn;
13	import io.strimzi.crdgenerator.annotations.Crd;
14	import io.strimzi.crdgenerator.annotations.Description;
15	import io.strimzi.crdgenerator.annotations.DescriptionFile;
16	import io.strimzi.crdgenerator.annotations.KubeLink;
17	import io.strimzi.crdgenerator.annotations.PresentInVersions;
18	
19	import java.io.File;
20	import java.io.FileOutputStream;
21	import java.io.IOException;
22	import java.io.OutputStreamWriter;
23	import java.lang.reflect.Method;
24	import java.nio.charset.StandardCharsets;
25	import java.util.ArrayList;
26	import java.util.Comparator;
27	import java.util.HashMap;
28	import java.util.HashSet;
29	import java.util.LinkedHashSet;
30	import java.util.List;
31	import java.util.Locale;
32	import java.util.Map;
33	import java.util.Set;
34	import java.util.regex.Pattern;
35	import java.util.stream.Collectors;
36	
37	import static io.strimzi.crdgenerator.Property.discriminator;
38	import static io.strimzi.crdgenerator.Property.isPolymorphic;
39	import static io.strimzi.crdgenerator.Property.properties;
40	import static io.strimzi.crdgenerator.Property.subtypeMap;
41	import static io.strimzi.crdgenerator.Property.subtypes;
42	import static java.util.Collections.emptySet;
43	import static java.util.Collections.singletonList;
44	
45	class DocGenerator {
46	
47	    private static final String NL = System.lineSeparator();
48	    private static final Pattern DOT_AT_THE_END = Pattern.compile(".*[.!?]$", Pattern.DOTALL);
49	
50	    private final int headerDepth;
51	    private final Appendable out;
52	    private final ApiVersion crApiVersion;
53	
54	    private final Set<Class<?>> documentedTypes = new HashSet<>();
55	    private final HashMap<Class<?>, Set<Class<?>>> usedIn;
56	    private final Linker linker;
57	    private int numErrors = 0;
58	
59	    public DocGenerator(ApiVersion crApiVersion, int headerDepth, Iterable<Class<? extends CustomResource>> crdClasses, Appendable out, Linker linker) {
60	        this.crApiVersion = crApiVersion;
61	        this.out = out;
62	        this.headerDepth = headerDepth;
63	        this.linker = linker;
64	        this.usedIn = new HashMap<>();
65	        for (Class<? extends CustomResource> crdClass: crdClasses) {
66	            usedIn(crdClass, usedIn);
67	        }
68	    }
69	
70	    private void appendAnchor(Class<?> anchor) throws IOException {
71	        out.append("[id='").append(anchor(anchor)).append("']").append(NL);
72	    }
73	
74	    private String anchor(Class<?> anchor) {
75	        return "type-" + anchor.getSimpleName() + "-{context}";
76	    }
77	
78	    private void appendHeading(String name) throws IOException {
79	        appendRepeated('=', headerDepth);
80	        out.append(' ');
81	        out.append(name);
82	        out.append(" schema reference");
83	
84	        out.append(NL);
85	        out.append(NL);
86	    }
87	
88	    private void usedIn(Class<?> cls, Map<Class<?>, Set<Class<?>>> usedIn) {
89	        Set<Property> memorableProperties = new HashSet<>();
90	
91	        for (Property property : properties(crApiVersion, cls).values()) {
92	            if (property.isAnnotationPresent(KubeLink.class)) {
93	                continue;
94	            }
95	
96	            memorableProperties.add(property);
97	        }
98	
99	        for (Property property : memorableProperties) {
100	            PropertyType propertyType = property.getType();
101	            Class<?> type = propertyType.isArray() ? propertyType.arrayBase() : propertyType.getType();
102	            for (Class<?> c : subtypesOrSelf(type)) {
103	                if (Schema.isJsonScalarType(c)) {
104	                    continue;
105	                }
106	
107	                Set<Class<?>> classes = getOrCreateClassesSet(c, usedIn);
108	
109	                classes.add(cls);
110	
111	                usedIn(c, usedIn);
112	            }
113	        }
114	    }
115	
116	    private Set<Class<?>> getOrCreateClassesSet(Class<?> c, Map<Class<?>, Set<Class<?>>> usedIn)   {
117	        return usedIn.computeIfAbsent(c, cls -> new HashSet<>(1));
118	    }
119	
120	    private List<? extends Class<?>> subtypesOrSelf(Class<?> returnType) {
121	        return isPolymorphic(returnType) ? subtypes(crApiVersion, returnType) : singletonList(returnType);
122	    }
123	
124	    public void generate(Class<? extends CustomResource> crdClass) throws IOException {
125	        Crd crd = crdClass.getAnnotation(Crd.class);
126	        appendAnchor(crdClass);
127	        appendHeading("`" + crd.spec().names().kind() + "`");
128	        appendCommonTypeDoc(crd, crdClass);
129	    }
130	
131	    private void appendedNestedTypeDoc(Crd crd, Class<?> cls) throws IOException {
132	        appendAnchor(cls);
133	        appendHeading("`" + cls.getSimpleName() + "`");
134	        appendCommonTypeDoc(crd, cls);
135	    }
136	
137	    private void appendCommonTypeDoc(Crd crd, Class<?> cls) throws IOException {
138	        appendTypeDeprecation(crd, cls);
139	        appendUsedIn(crd, cls);
140	        appendDescription(cls);
141	        appendDiscriminator(crd, cls);
142	    
143	        out.append("[cols=\"2,2,3a\",options=\"header\"]").append(NL);
144	        out.append("|====").append(NL);
145	        out.append("|Property |Property type |Description").append(NL);
146	    
147	        LinkedHashSet<Class<?>> types = new LinkedHashSet<>();
148	    
149	        for (Map.Entry<String, Property> entry : properties(crApiVersion, cls).entrySet()) {
150	            String propertyName = entry.getKey();
151	            final Property property = entry.getValue();
152	            PropertyType propertyType = property.getType();
153	        
154	            // Set the external link to Kubernetes docs or the link for fields distinguished by `type`
155	            KubeLink kubeLink = property.getAnnotation(KubeLink.class);
156	            String externalUrl = linker != null && kubeLink != null ? linker.link(kubeLink) : null;
157	        
158	            // Add the property name
159	            out.append("|").append(propertyName);
160	        
161	            // Add the property type description
162	            appendPropertyType(crd, out, propertyType, externalUrl);
163	        
164	            // Set warning message for deprecated fields
165	            addDeprecationWarning(property);
166	        
167	            // Add the version the field was added in
168	            addAddedIn(property);
169	        
170	            // Add the types to the `types` array to also generate the docs for the type itself
171	            Class<?> documentedType = propertyType.isArray() ? propertyType.arrayBase() : propertyType.getType();
172	        
173	            if (externalUrl == null
174	                && !Schema.isJsonScalarType(documentedType)
175	                && !documentedType.equals(Map.class)
176	                && !documentedType.equals(Object.class)) {
177	                types.add(documentedType);
178	            }
179	        
180	            // Add the property description
181	            addDescription(cls, property);
182	        
183	            out.append(NL);
184	        }
185	        
186	        out.append("|====").append(NL).append(NL);
187	    
188	        appendNestedTypes(crd, types);
189	    }    
190	
191	    /**
192	     * Sets warning message for deprecated fields
193	     *
194	     * @param property  The property which will be checked for deprecation
195	     *
196	     * @throws IOException  Throws IOException when appending to the output fails
197	     */
198	    private void addDeprecationWarning(Property property) throws IOException {
199	        DeprecatedProperty strimziDeprecated = property.getAnnotation(DeprecatedProperty.class);
200	        Deprecated langDeprecated = property.getAnnotation(Deprecated.class);
201	
202	        if (strimziDeprecated != null || langDeprecated != null) {
203	            if (strimziDeprecated == null || langDeprecated == null) {
204	                err(property + " must be annotated with both @" + Deprecated.class.getName()
205	                        + " and @" + DeprecatedProperty.class.getName());
206	            }
207	            if (strimziDeprecated != null) {
208	                out.append(getDeprecation(property, strimziDeprecated));
209	            }
210	        }
211	    }
212	
213	    /**
214	     * Sets the description for given property
215	     *
216	     * @param cls   The Class (type) which is being documented
217	     * @param property  The property for which the description should be added
218	     *
219	     * @throws IOException  Throws IOException when appending to the output fails
220	     */
221	    private void addDescription(Class<?> cls, Property property) throws IOException {
222	        Description description = property.getAnnotation(Description.class);
223	
224	        if (description == null) {
225	            if (cls.getName().startsWith("io.strimzi")) {
226	                err(property + " is not documented");
227	            }
228	        } else {
229	            out.append(getDescription(description));
230	        }
231	    }
232	
233	    /**
234	     * Sets the version in which the property was added. It is done only for properties that have the AddedIn annotation.
235	     *
236	     * @param property  The property for which the version should be added
237	     *
238	     * @throws IOException  Throws IOException when appending to the output fails
239	     */
240	    private void addAddedIn(Property property) throws IOException {
241	        AddedIn addedIn = property.getAnnotation(AddedIn.class);
242	
243	        if (addedIn != null) {
244	            out.append("Added in Strimzi " + addedIn.value() + ". ");
245	        }
246	    }
247	
248	    private String getDeprecation(Property property, DeprecatedProperty deprecated) {
249	        String msg = String.format("**The `%s` property has been deprecated",
250	                property.getName());
251	        if (!deprecated.movedToPath().isEmpty()) {
252	            msg += ", and should now be configured using `" + deprecated.movedToPath() + "`";
253	        }
254	        if (!deprecated.removalVersion().isEmpty()) {
255	            msg += ". The property " + property.getName() + " is removed in API version `" + deprecated.removalVersion() + "`";
256	        }
257	        msg += ".** ";
258	        if (!deprecated.description().isEmpty()) {
259	            msg += deprecated.description() + " ";
260	        }
261	
262	        return msg;
263	    }
264	
265	    static String getDescription(Description description) {
266	        String doc = description.value();
267	        if (!DOT_AT_THE_END.matcher(doc.trim()).matches())  {
268	            doc = doc + ".";
269	        }
270	        doc = doc.replaceAll("[|]", "\\\\|");
271	        return doc;
272	    }
273	
274	    private void err(String s) {
275	        System.err.println(DocGenerator.class.getSimpleName() + ": error: " + s);
276	        numErrors++;
277	    }
278	
279	    private void appendNestedTypes(Crd crd, LinkedHashSet<Class<?>> types) throws IOException {
280	        for (Class<?> type : types) {
281	            for (Class<?> t2 : subtypesOrSelf(type)) {
282	                if (!documentedTypes.contains(t2)) {
283	                    appendedNestedTypeDoc(crd, t2);
284	                    this.documentedTypes.add(t2);
285	                }
286	            }
287	        }
288	    }
289	
290	    private void appendPropertyType(Crd crd, Appendable out, PropertyType propertyType, String externalUrl) throws IOException {
291	        Class<?> propertyClass = propertyType.isArray() ? propertyType.arrayBase() : propertyType.getType();
292	
293	        out.append(NL);
294	        out.append("|");
295	        
296	        // Now the type link
297	        if (externalUrl != null) {
298	            out.append(externalUrl).append("[").append(propertyClass.getSimpleName()).append("]");
299	        } else if (propertyType.isEnum()) {
300	            Set<String> strings = new HashSet<>();
301	            for (JsonNode n : Schema.enumCases(propertyType.getEnumElements())) {
302	                if (n.isTextual()) {
303	                    strings.add(n.asText());
304	                } else {
305	                    throw new RuntimeException("Enum case is not a string");
306	                }
307	            }
308	            out.append("string (one of " + strings + ")");
309	        } else if (propertyType.isArray() && propertyType.arrayBase().isEnum()) {
310	            try {
311	                Set<String> strings = new HashSet<>();
312	                Method valuesMethod = propertyType.arrayBase().getMethod("values");
313	
314	                for (JsonNode n : Schema.enumCases((Enum<?>[]) valuesMethod.invoke(null))) {
315	                    if (n.isTextual()) {
316	                        strings.add(n.asText());
317	                    } else {
318	                        throw new RuntimeException("Enum case is not a string");
319	                    }
320	                }
321	                out.append("string (one or more of " + strings + ")");
322	            } catch (ReflectiveOperationException e) {
323	                throw new RuntimeException(e);
324	            }
325	        } else {
326	            typeLink(crd, out, propertyClass);
327	        }
328	        if (propertyType.isArray()) {
329	            out.append(" array");
330	            int dim = propertyType.arrayDimension();
331	            if (dim > 1) {
332	                out.append(" of dimension ").append(String.valueOf(dim));
333	            }
334	        }
335	
336	        out.append(NL);
337	        out.append("|");
338	    }
339	
340	    private void appendTypeDeprecation(Crd crd, Class<?> cls) throws IOException {
341	        DeprecatedType deprecatedType = cls.getAnnotation(DeprecatedType.class);
342	        Deprecated langDeprecated = cls.getAnnotation(Deprecated.class);
343	
344	        if (deprecatedType != null || langDeprecated != null) {
345	            if (deprecatedType == null || langDeprecated == null) {
346	                err(cls.getName() + " must be annotated with both @" + Deprecated.class.getName()
347	                        + " and @" + DeprecatedType.class.getName());
348	            }
349	            if (deprecatedType != null
350	                    && deprecatedType.replacedWithType() != null) {
351	                Class<?> replacementClss = deprecatedType.replacedWithType();
352	
353	                out.append("*The type `" + cls.getSimpleName() + "` has been deprecated");
354	                if (!deprecatedType.removalVersion().isEmpty()) {
355	                    out.append(" and is removed in API version `" + deprecatedType.removalVersion() + "`");
356	                }
357	                out.append(".*").append(NL);
358	
359	                if (replacementClss != void.class) {
360	                    out.append("Please use ");
361	                    typeLink(crd, out, replacementClss);
362	                    out.append(" instead.").append(NL);
363	                }
364	
365	                out.append(NL);
366	            }
367	        }
368	    }
369	
370	    private void appendDescription(Class<?> cls) throws IOException {
371	        DescriptionFile descriptionFile = cls.getAnnotation(DescriptionFile.class);
372	        Description description = cls.getAnnotation(Description.class);
373	
374	        if (descriptionFile != null)    {
375	            String filename = "api/" + cls.getCanonicalName() + ".adoc";
376	            File includeFile = new File(filename);
377	
378	            if (!includeFile.isFile())   {
379	                throw new RuntimeException("Class " + cls.getCanonicalName() + " has @DescriptionFile annotation, but file " + filename + " does not exist!");
380	            }
381	
382	            out.append("xref:type-").append(cls.getSimpleName()).append("-schema-{context}[Full list of `").append(cls.getSimpleName()).append("` schema properties]").append(NL);
383	            out.append(NL);
384	            out.append("include::../" + filename + "[leveloffset=+1]").append(NL);
385	            out.append(NL);
386	            out.append("[id='type-").append(cls.getSimpleName()).append("-schema-{context}']").append(NL);
387	            out.append("== `").append(cls.getSimpleName()).append("` schema properties").append(NL);
388	            out.append(NL);
389	
390	        } else if (description != null) {
391	            out.append(getDescription(description)).append(NL);
392	        }
393	        out.append(NL);
394	    }
395	
396	    private void appendUsedIn(Crd crd, Class<?> cls) throws IOException {
397	        List<Class<?>> usedIn = new ArrayList<>(this.usedIn.getOrDefault(cls, emptySet()));
398	        usedIn.sort(Comparator.comparing(c -> c.getSimpleName().toLowerCase(Locale.ENGLISH)));
399	        if (!usedIn.isEmpty()) {
400	            out.append("Used in: ");
401	            boolean first = true;
402	            for (Class<?> usingClass : usedIn) {
403	                if (!first) {
404	                    out.append(", ");
405	                }
406	                typeLink(crd, out, usingClass);
407	                first = false;
408	            }
409	            out.append(NL);
410	            out.append(NL);
411	        }
412	    }
413	
414	    private void appendDiscriminator(Crd crd, Class<?> cls) throws IOException {
415	        String discriminator = discriminator(cls.getSuperclass());
416	        if (discriminator != null) {
417	            if (cls.isAnnotationPresent(PresentInVersions.class)) {
418	                // Adds a note about presence in different versions
419	                out.append("The type ")
420	                        .append(cls.getSimpleName())
421	                        .append(" is supported only in the Strimzi API version(s) ")
422	                        .append(ApiVersion.parseRange(cls.getAnnotation(PresentInVersions.class).value()).toString())
423	                        .append(".")
424	                        .append(NL)
425	                        .append(NL);
426	            }
427	
428	            String subtypeLinks = subtypes(crApiVersion, cls.getSuperclass()).stream().filter(c -> !c.equals(cls)).map(c -> {
429	                try {
430	                    return typeLink(crd, c);
431	                } catch (IOException e) {
432	                    throw new RuntimeException(e);
433	                }
434	            }).collect(Collectors.joining(", "));
435	            out.append("The `").append(discriminator)
436	                    .append("` property is a discriminator that distinguishes use of the `")
437	                    .append(cls.getSimpleName()).append("` type from ");
438	            if (subtypeLinks.trim().isEmpty()) {
439	                out.append("other subtypes that may be added in the future.");
440	            } else {
441	                out.append(subtypeLinks).append(".");
442	            }
443	            out.append(NL);
444	            out.append("It must have the value `").append(subtypeMap(cls.getSuperclass()).get(cls)).append("` for the type `").append(cls.getSimpleName()).append("`.").append(NL);
445	        }
446	    }
447	
448	    private void appendRepeated(char c, int num) throws IOException {
449	        for (int i = 0; i < num; i++) {
450	            out.append(c);
451	        }
452	    }
453	
454	    public void typeLink(Crd crd, Appendable out, Class<?> cls) throws IOException {
455	        if (short.class.equals(cls)
456	                || Short.class.equals(cls)
457	                || int.class.equals(cls)
458	                || Integer.class.equals(cls)
459	                || long.class.equals(cls)
460	                || Long.class.equals(cls)) {
461	            out.append("integer");
462	        } else if (Float.class.equals(cls)
463	                || float.class.equals(cls)
464	                || Double.class.equals(cls)
465	                || double.class.equals(cls)) {
466	            out.append("number");
467	        } else if (Object.class.equals(cls)
468	                || String.class.equals(cls)
469	                || Map.class.equals(cls)
470	                || Boolean.class.equals(cls)
471	                || boolean.class.equals(cls)) {
472	            out.append(cls.getSimpleName().toLowerCase(Locale.ENGLISH));
473	        } else if (isPolymorphic(cls)) {
474	            out.append(subtypes(crApiVersion, cls).stream().map(c -> {
475	                try {
476	                    return typeLink(crd, c);
477	                } catch (IOException e) {
478	                    throw new RuntimeException(e);
479	                }
480	            }).collect(Collectors.joining(", ")));
481	        } else {
482	            out.append("xref:").append(anchor(cls)).append("[`").append(cls.getSimpleName()).append("`]");
483	        }
484	    }
485	
486	    public String typeLink(Crd crd, Class<?> cls) throws IOException {
487	        StringBuilder sb = new StringBuilder();
488	        typeLink(crd, sb, cls);
489	        return sb.toString();
490	    }
491	
492	    public static void main(String[] args) throws IOException, ClassNotFoundException {
493	        Linker linker = null;
494	        File out = null;
495	        List<Class<? extends CustomResource>> classes = new ArrayList<>();
496	
497	        for (int i = 0; i < args.length; i++) {
498	            String arg = args[i];
499	            if (arg.startsWith("-")) {
500	                if ("--linker".equals(arg)) {
501	                    String className = args[++i];
502	                    Class<? extends Linker> linkerClass = classInherits(Class.forName(className), Linker.class);
503	                    if (linkerClass != null) {
504	                        try {
505	                            linker = linkerClass.getConstructor(String.class).newInstance(args[++i]);
506	                        } catch (ReflectiveOperationException e) {
507	                            throw new RuntimeException("--linker option can't be handled", e);
508	                        }
509	                    } else {
510	                        System.err.println(className + " is not a subclass of " + Linker.class.getName());
511	                    }
512	                } else {
513	                    throw new RuntimeException("Unsupported option " + arg);
514	                }
515	            } else {
516	                if (out == null) {
517	                    out = new File(arg);
518	                } else {
519	                    // If we have fallen in the else branch here, the arg has to be a class name
520	                    Class<? extends CustomResource> cls = classInherits(Class.forName(arg), CustomResource.class);
521	                    if (cls != null) {
522	                        classes.add(cls);
523	                    } else {
524	                        System.err.println(arg + " is not a subclass of " + CustomResource.class.getName());
525	                    }
526	                }
527	            }
528	        }
529	
530	        ApiVersion crApiVersion = ApiVersion.V1;
531	
532	        try (OutputStreamWriter writer = new OutputStreamWriter(new FileOutputStream(out), StandardCharsets.UTF_8)) {
533	            writer.append(":_mod-docs-content-type: REFERENCE").append(NL).append(NL);
534	            writer.append("// This file is auto-generated by ")
535	                .append(DocGenerator.class.getName())
536	                .append(".").append(NL);
537	            writer.append("// To change this documentation you need to edit the Java sources.").append(NL);
538	            writer.append(NL);
539	            DocGenerator dg = new DocGenerator(crApiVersion, 1, classes, writer, linker);
540	            for (Class<? extends CustomResource> c : classes) {
541	                dg.generate(c);
542	            }
543	            if (dg.numErrors > 0) {
544	                System.err.println("There were " + dg.numErrors + " errors");
545	                System.exit(1);
