                        .append(cls.getSimpleName())
                        .append(" is supported only in the Strimzi API version(s) ")
                        .append(ApiVersion.parseRange(cls.getAnnotation(PresentInVersions.class).value()).toString())
                        .append(".")
                        .append(NL)
                        .append(NL);
